const body = $input.item.json.body;
const errors = [];

if (!body.brand) errors.push('brand required');
if (!body.product) errors.push('product required');
if (!body.objective) errors.push('objective required');
if (!body.dailyBudgetUSD || body.dailyBudgetUSD < 5) errors.push('dailyBudgetUSD must be >= 5');
if (!body.targetCountries?.length) errors.push('targetCountries required (array)');
if (!body.startDate) errors.push('startDate required');

const validObjectives = ['OUTCOME_LEADS','OUTCOME_SALES','OUTCOME_AWARENESS','OUTCOME_TRAFFIC'];
if (body.objective && !validObjectives.includes(body.objective)) errors.push(`Invalid objective. Must be: ${validObjectives.join(', ')}`);

if (errors.length) {
  return [{ json: { valid: false, errors } }];
}

return [{ json: { valid: true, brief: body } }];

