const text = $input.item.json.content?.[0]?.text ?? '{}';
const clean = text.replace(/```(?:json)?\n?/g, '').trim();
try {
  const payload = JSON.parse(clean);
  const brief = $('IF — Valid brief?').item.json.brief;
  return [{ json: { payload, brief } }];
} catch (e) {
  throw new Error('Claude returned invalid JSON: ' + e.message);
}

